-- Migration Script
-- Strategy: Create new table, migrate data with type conversion, swap tables, create indexes.
-- This ensures atomicity and minimizes downtime by avoiding long-running ALTER TABLE operations on the live table.

BEGIN TRANSACTION;

-- 1. Create the new table with the target schema
CREATE TABLE transactions_new (
    id INT PRIMARY KEY,
    customer_id INT NOT NULL,
    amount DECIMAL(18, 2) NOT NULL,
    notes TEXT,
    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2. Migrate data with safe conversion
-- Handles NULL values in 'amount' by defaulting to 0.00 (adjust logic if NULLs should be rejected)
INSERT INTO transactions_new (id, customer_id, amount, notes, timestamp)
SELECT 
    id, 
    customer_id, 
    CASE 
        WHEN amount IS NULL OR amount = '' THEN 0.00
        ELSE CAST(amount AS DECIMAL(18, 2))
    END,
    notes,
    CURRENT_TIMESTAMP
FROM transactions
WHERE amount IS NOT NULL AND amount != '';

-- 3. Create the required composite index
CREATE INDEX idx_customer_timestamp ON transactions_new (customer_id, timestamp);

-- 4. Swap tables (Atomic operation in most modern RDBMS like PostgreSQL, MySQL 8.0+)
-- Note: In MySQL, use RENAME TABLE; in PostgreSQL, use ALTER TABLE ... RENAME.
-- Assuming standard SQL compatible with PostgreSQL/MySQL for this example:

RENAME TABLE transactions TO transactions_legacy;
RENAME TABLE transactions_new TO transactions;

COMMIT;

-- Rollback Strategy
-- If the migration fails or data integrity checks fail, execute the following immediately:

BEGIN TRANSACTION;

-- 1. Drop the new table (if it exists)
DROP TABLE IF EXISTS transactions;

-- 2. Restore the original table name
RENAME TABLE transactions_legacy TO transactions;

COMMIT;

-- Post-Migration Verification (Recommended)
-- SELECT COUNT(*) FROM transactions;
-- SELECT COUNT(*) FROM transactions_legacy;
-- Ensure counts match before dropping transactions_legacy permanently.

