-- 1. Create the role
CREATE ROLE nurse_readonly;

-- 2. Grant SELECT on the patients table to the role
GRANT SELECT ON patients TO nurse_readonly;

-- 3. Revoke access to sensitive columns (ssn, diagnosis)
REVOKE SELECT (ssn, diagnosis) ON patients FROM nurse_readonly;

-- 4. Create the stored procedure with parameterized audit validation
CREATE OR REPLACE PROCEDURE update_patient_status(
    p_patient_id INT,
    p_new_status VARCHAR(50),
    p_audit_log_id INT
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_log_exists BOOLEAN;
BEGIN
    -- Validate that the audit_log_id exists in the audit_log table
    SELECT EXISTS(SELECT 1 FROM audit_log WHERE id = p_audit_log_id) INTO v_log_exists;

    IF NOT v_log_exists THEN
        RAISE EXCEPTION 'Invalid audit_log_id: The provided ID does not exist in the audit_log table.';
    END IF;

    -- Update the patient status
    UPDATE patients
    SET status = p_new_status
    WHERE id = p_patient_id;

    -- Optional: Log the action explicitly if not handled by the audit_log table trigger
    -- INSERT INTO audit_log (action, timestamp) VALUES ('UPDATE_STATUS', NOW());
END;
$$;

-- 5. Grant EXECUTE permission on the procedure to authorized staff (e.g., 'authorized_staff' role)
-- Note: Replace 'authorized_staff' with the actual role name for authorized personnel
GRANT EXECUTE ON PROCEDURE update_patient_status TO authorized_staff;
