-- 1. Create Roles
CREATE ROLE support_agent;
CREATE ROLE manager;
CREATE ROLE admin;

-- 2. Create a table to map users to their assigned tenant (Assuming a 'users' table exists or is created)
-- If 'users' table does not exist, create it:
CREATE TABLE IF NOT EXISTS users (
    user_id SERIAL PRIMARY KEY,
    username VARCHAR(50) UNIQUE NOT NULL,
    tenant_id INT NOT NULL
);

-- 3. Grant Table-Level Permissions
-- Support Agent: Read access to public_data and customer_data
GRANT SELECT ON public_data TO support_agent;
GRANT SELECT ON customer_data TO support_agent;

-- Manager: Read and Write access to customer_data
GRANT SELECT, INSERT, UPDATE, DELETE ON customer_data TO manager;

-- Admin: Full access to all tables
GRANT ALL PRIVILEGES ON ALL TABLES IN SCHEMA public TO admin;
GRANT ALL PRIVILEGES ON ALL SEQUENCES IN SCHEMA public TO admin;

-- 4. Implement Row-Level Security (RLS) for Support Agents
-- Enable RLS on customer_data
ALTER TABLE customer_data ENABLE ROW LEVEL SECURITY;

-- Create a policy that restricts support_agent to their assigned tenant
-- This assumes the current user's tenant_id is stored in a session variable or a mapping table.
-- Here we assume a function `current_user_tenant_id()` returns the tenant_id for the logged-in user.
-- If using a standard mapping table 'users', we use a join approach via a helper function or trigger.

-- Option A: Using a helper function (Recommended for dynamic tenant lookup)
CREATE OR REPLACE FUNCTION get_user_tenant_id()
RETURNS INT AS $$
BEGIN
    RETURN (SELECT tenant_id FROM users WHERE username = current_user);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Create the RLS Policy
CREATE POLICY support_agent_tenant_isolation ON customer_data
    FOR SELECT
    TO support_agent
    USING (tenant_id = get_user_tenant_id());

-- 5. Grant Usage on Schema (Required for RLS to function properly in some DBs)
GRANT USAGE ON SCHEMA public TO support_agent;
GRANT USAGE ON SCHEMA public TO manager;
GRANT USAGE ON SCHEMA public TO admin;

-- 6. Ensure Default Deny for other tables if necessary (Optional but good practice)
-- Revoke public access if not intended
REVOKE ALL ON ALL TABLES IN SCHEMA public FROM PUBLIC;
```
